import { useParams, Link } from 'react-router-dom';

// Definição da rota:
// { path: '/produto/:id', element: <ProdutoDetalhe /> }

function ProdutoDetalhe() {
  const { id } = useParams();  // { id: '42' } quando URL = /produto/42

  return (
    <div>
      <h1>Produto #{id}</h1>
      <p>Carregando detalhes do produto {id}...</p>
    </div>
  );
}

// Rota: /curso/:cursoId/aula/:aulaId
// URL:  /curso/react/aula/jsx

function Aula() {
  const { cursoId, aulaId } = useParams();
  // cursoId = 'react', aulaId = 'jsx'

  return <h1>{cursoId} — Aula: {aulaId}</h1>;
}

const produtos = [
  { id: 1, nome: 'React' },
  { id: 2, nome: 'TypeScript' },
  { id: 3, nome: 'Tailwind' },
];

function ListaProdutos() {
  return (
    <ul>
      {produtos.map(p => (
        <li key={p.id}>
          <Link to={`/produto/${p.id}`}>{p.nome}</Link>
        </li>
      ))}
    </ul>
  );
}

const router = createBrowserRouter([
  { path: '/produtos', element: <ListaProdutos /> },
  { path: '/produtos/:id', element: <ProdutoDetalhe /> },
]);

