challenge.solution:
import {
  createBrowserRouter,
  RouterProvider,
  Link,
  Outlet,
  useParams,
} from 'react-router-dom';

const users = [
  { id: 1, name: 'Maria' },
  { id: 2, name: 'João' },
  { id: 3, name: 'Ana' },
];

function UserList() {
  return (
    <div>
      <h1 className="text-xl font-bold mb-4">Usuários</h1>
      <ul className="space-y-2">
        {users.map(u => (
          <li key={u.id}>
            <Link to={`/users/${u.id}`} className="text-blue-500 hover:underline">
              {u.name}
            </Link>
          </li>
        ))}
      </ul>
    </div>
  );
}

function UserDetail() {
  const { id } = useParams();
  const user = users.find(u => u.id === Number(id));

  if (!user) return <p>Usuário não encontrado.</p>;

  return (
    <div>
      <h1 className="text-xl font-bold">Perfil do usuário #{id}</h1>
      <p className="mt-2">Nome: {user.name}</p>
      <Link to="/users" className="mt-4 inline-block text-blue-500 hover:underline">
        ← Voltar para a lista
      </Link>
    </div>
  );
}

function Layout() {
  return (
    <div>
      <nav className="p-4 border-b">
        <Link to="/users">Usuários</Link>
      </nav>
      <main className="p-4"><Outlet /></main>
    </div>
  );
}

const router = createBrowserRouter([
  {
    element: <Layout />,
    children: [
      { path: '/users', element: <UserList /> },
      { path: '/users/:id', element: <UserDetail /> },
    ],
  },
]);

export default function App() {
  return <RouterProvider router={router} />;
}
